import{_ as o,c as r,o as i,ag as e}from"./chunks/framework.Co20b0ok.js";const u=JSON.parse('{"title":"HTTP 协议","description":"","frontmatter":{},"headers":[],"relativePath":"security/protocol/HTTP.md","filePath":"security/protocol/HTTP.md"}'),n={name:"security/protocol/HTTP.md"};function l(s,t,a,g,d,h){return i(),r("div",null,t[0]||(t[0]=[e('<h1 id="http-协议" tabindex="-1">HTTP 协议 <a class="header-anchor" href="#http-协议" aria-label="Permalink to &quot;HTTP 协议&quot;">​</a></h1><h2 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h2><h2 id="https" tabindex="-1">HTTPS <a class="header-anchor" href="#https" aria-label="Permalink to &quot;HTTPS&quot;">​</a></h2><h2 id="常见状态码" tabindex="-1">常见状态码 <a class="header-anchor" href="#常见状态码" aria-label="Permalink to &quot;常见状态码&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态码</th><th>说明</th></tr></thead><tbody><tr><td>200</td><td>响应成功</td></tr><tr><td>302</td><td>跳转，通过响应头中的location属性指定</td></tr><tr><td>400</td><td>客户端请求语法有错误，不能被服务器识别</td></tr><tr><td>403</td><td>服务器接收到请求，但是拒绝服务，也即是认证失败</td></tr><tr><td>404</td><td>请求资源不存在</td></tr><tr><td>500</td><td>服务器内部错误</td></tr></tbody></table><h2 id="详细点的" tabindex="-1">详细点的 <a class="header-anchor" href="#详细点的" aria-label="Permalink to &quot;详细点的&quot;">​</a></h2><h3 id="xx-信息性响应" tabindex="-1">xx：信息性响应 <a class="header-anchor" href="#xx-信息性响应" aria-label="Permalink to &quot;xx：信息性响应&quot;">​</a></h3><ul><li><strong>100 Continue</strong>：客户端应继续请求。</li><li><strong>101 Switching Protocols</strong>：服务器根据客户端请求切换协议。</li><li><strong>102 Processing (WebDAV)</strong>：服务器已收到并正在处理请求，但无响应可用。</li></ul><h3 id="_2xx-成功" tabindex="-1">2xx：成功 <a class="header-anchor" href="#_2xx-成功" aria-label="Permalink to &quot;2xx：成功&quot;">​</a></h3><ul><li><strong>200 OK</strong>：请求成功并返回所请求的资源。</li><li><strong>201 Created</strong>：请求成功，已创建新资源。</li><li><strong>202 Accepted</strong>：请求已接受，但尚未处理完成。</li><li><strong>203 Non-Authoritative Information</strong>：请求成功，但返回的元数据并非原始服务器的。</li><li><strong>204 No Content</strong>：请求成功但无内容返回。</li><li><strong>205 Reset Content</strong>：请求成功，但客户端应重置视图。</li><li><strong>206 Partial Content</strong>：请求成功，只返回部分内容（用于分块下载）。</li></ul><h3 id="_3xx-重定向" tabindex="-1">3xx：重定向 <a class="header-anchor" href="#_3xx-重定向" aria-label="Permalink to &quot;3xx：重定向&quot;">​</a></h3><ul><li><strong>300 Multiple Choices</strong>：请求的资源有多种表示，用户或客户端可以选择。</li><li><strong>301 Moved Permanently</strong>：请求的资源已永久移动到新URL。</li><li><strong>302 Found</strong>：请求的资源暂时在另一个URL，客户端应继续使用原URL进行请求。</li><li><strong>303 See Other</strong>：资源在另一个URL，客户端应使用GET方法获取资源。</li><li><strong>304 Not Modified</strong>：资源未修改，客户端可继续使用缓存版本。</li><li><strong>305 Use Proxy</strong>：请求的资源必须通过代理访问。</li><li><strong>307 Temporary Redirect</strong>：请求的资源暂时在另一个URL，客户端应继续使用原URL进行请求。</li><li><strong>308 Permanent Redirect</strong>：请求的资源已永久移动到新URL，客户端应使用新URL进行请求。</li></ul><h3 id="_4xx-客户端错误" tabindex="-1">4xx：客户端错误 <a class="header-anchor" href="#_4xx-客户端错误" aria-label="Permalink to &quot;4xx：客户端错误&quot;">​</a></h3><ul><li><strong>400 Bad Request</strong>：请求无效，服务器无法理解。</li><li><strong>401 Unauthorized</strong>：请求未授权，客户端需提供认证信息。</li><li><strong>402 Payment Required</strong>：保留状态码，暂未使用。</li><li><strong>403 Forbidden</strong>：服务器拒绝请求，客户端无权访问。</li><li><strong>404 Not Found</strong>：请求的资源不存在。</li><li><strong>405 Method Not Allowed</strong>：请求方法不被允许。</li><li><strong>406 Not Acceptable</strong>：请求的资源不满足客户端的条件。</li><li><strong>407 Proxy Authentication Required</strong>：需要代理认证。</li><li><strong>408 Request Timeout</strong>：请求超时，服务器未收到完整请求。</li><li><strong>409 Conflict</strong>：请求冲突，资源的当前状态与请求不兼容。</li><li><strong>410 Gone</strong>：请求的资源已永久删除。</li><li><strong>411 Length Required</strong>：请求未提供Content-Length头部。</li><li><strong>412 Precondition Failed</strong>：请求条件未满足。</li><li><strong>413 Payload Too Large</strong>：请求体过大。</li><li><strong>414 URI Too Long</strong>：请求的URI过长。</li><li><strong>415 Unsupported Media Type</strong>：请求的媒体类型不被支持。</li><li><strong>416 Range Not Satisfiable</strong>：请求的范围无效。</li><li><strong>417 Expectation Failed</strong>：服务器无法满足Expect头部的要求。</li><li><strong>418 I&#39;m a teapot</strong>：愚人节笑话状态码，不会煮咖啡的茶壶。</li><li><strong>421 Misdirected Request</strong>：请求重定向到错误的服务器。</li><li><strong>422 Unprocessable Entity (WebDAV)</strong>：请求格式正确但无法处理。</li><li><strong>423 Locked (WebDAV)</strong>：资源被锁定。</li><li><strong>424 Failed Dependency (WebDAV)</strong>：请求因之前的失败而失败。</li><li><strong>425 Too Early</strong>：服务器不愿处理可能重播的请求。</li><li><strong>426 Upgrade Required</strong>：需要客户端升级协议。</li><li><strong>428 Precondition Required</strong>：请求需满足先决条件。</li><li><strong>429 Too Many Requests</strong>：客户端发送了太多请求。</li><li><strong>431 Request Header Fields Too Large</strong>：请求头部字段太大。</li><li><strong>451 Unavailable For Legal Reasons</strong>：资源因法律原因不可用。</li></ul><h3 id="_5xx-服务器错误" tabindex="-1">5xx：服务器错误 <a class="header-anchor" href="#_5xx-服务器错误" aria-label="Permalink to &quot;5xx：服务器错误&quot;">​</a></h3><ul><li><strong>500 Internal Server Error</strong>：服务器内部错误。</li><li><strong>501 Not Implemented</strong>：服务器不支持请求的方法。</li><li><strong>502 Bad Gateway</strong>：网关或代理收到无效响应。</li><li><strong>503 Service Unavailable</strong>：服务器暂时无法处理请求（超载或维护）。</li><li><strong>504 Gateway Timeout</strong>：网关或代理请求超时。</li><li><strong>505 HTTP Version Not Supported</strong>：服务器不支持请求的HTTP版本。</li><li><strong>506 Variant Also Negotiates</strong>：服务器内部配置错误。</li><li><strong>507 Insufficient Storage (WebDAV)</strong>：服务器存储不足。</li><li><strong>508 Loop Detected (WebDAV)</strong>：服务器检测到无限循环。</li><li><strong>510 Not Extended</strong>：请求需进一步扩展。</li><li><strong>511 Network Authentication Required</strong>：需要网络认证。</li></ul>',16)]))}const x=o(n,[["render",l]]);export{u as __pageData,x as default};
